// ---------------------------------------------------------------------------
// WIT interface: form-data
// ---------------------------------------------------------------------------

/** Type alias */
export type FormDataHandle = bigint;

/** Handle table for FormData instances */
const _formDatahandles = new Map<bigint, FormData>();
let _nextFormData = 1n;

/** Get a FormData by handle, throwing if not found. */
function getFormData(handle: bigint): FormData {
  const obj = _formDatahandles.get(handle);
  if (!obj) {
    throw new Error(`FormData handle ${handle} not found`);
  }
  return obj;
}

/**
 * `append()` operation.
 */
export function FormDataAppend(self: bigint, name: string, value: string): void {
  const obj = getFormData(self);
  obj.append(name, value);
}

/**
 * `delete()` operation.
 */
export function FormDataDelete(self: bigint, name: string): void {
  const obj = getFormData(self);
  obj.delete(name);
}

/**
 * `get()` operation.
 *
 * Async operation: returns request ID, poll with `FormDataPollGet()`
 */
export function FormDataGet(self: bigint, name: string): bigint {
  const requestId = _nextAsyncHandle++;
  const obj = getFormData(self);
  const promise = obj.get(name)
    .then((result) => {
      const entry = _asyncHandles.get(requestId);
      if (entry) {
        entry.result = { ok: true, value: result };
      }
    })
    .catch((err: Error) => {
      const entry = _asyncHandles.get(requestId);
      if (entry) {
        entry.result = { ok: false, error: err.message };
      }
    });

  _asyncHandles.set(requestId, { promise, result: null });
  return requestId;
}

/**
 * Poll an async `_get()` operation.
 * Returns undefined if still pending, or the result if complete.
 */
export function FormDataPollGet(requestId: bigint): { ok: true; value: bigint | undefined } | { ok: false; error: string } | undefined {
  const entry = _asyncHandles.get(requestId);
  if (!entry) {
    return { ok: false, error: `Unknown request ID ${requestId}` };
  }
  return entry.result as { ok: true; value: bigint | undefined } | { ok: false; error: string } | null ?? undefined;
}

/**
 * `get-all()` operation.
 */
export function getAll(self: bigint, name: string): (bigint)[] {
  const obj = getFormData(self);
  return obj.all;
}

/**
 * `has()` operation.
 */
export function FormDataHas(self: bigint, name: string): boolean {
  const obj = getFormData(self);
  return obj.has(name);
}

/**
 * `set()` operation.
 */
export function FormDataSet(self: bigint, name: string, value: string): void {
  const obj = getFormData(self);
  obj.set(name, value);
}

